+fn canonical_now(data: &[u8]) -> chrono::DateTime<Utc> {
+    let seed = i64::from(data.first().copied().unwrap_or(0));
+    Utc.timestamp_opt(1_700_000_000 + seed, 0)
+        .single()
+        .expect("fixed fuzz timestamp should be valid")
+}
